// outbox_id vem do nó Claim (pareamento de itens preservado).
const outboxId = $('Claim Batch').item.json.outbox_id;
const code = $json.statusCode;
const ok = typeof code === 'number' && code >= 200 && code < 300;
let erro = null;
if (!ok) {
  let b = $json.body;
  if (b && typeof b === 'object') b = JSON.stringify(b);
  erro = ('HTTP ' + (code ?? 'sem resposta') + ' ' + (b ?? '')).slice(0, 500);
}
return { json: { outbox_id: outboxId, ok, http_status: code ?? null, erro } };
